public static long solve(long[] weight) {
    long maxCount = 0;
    int i = 0;

    while (i < weight.length) {
        long maxWeight = weight[i];
        int j = i + 1;

        while (j < weight.length && weight[j] < maxWeight) {
            maxWeight = Math.max(maxWeight, weight[j]);
            j++;
        }

        if (weight[j - 1] < maxWeight) {
            maxCount++;
            i = j;
        } else {
            i++;
        }
    }

    return maxCount;
}
